118→							type="button"
119→							key={key}
120→							onClick={() => setSelectedMetric(key as MetricType)}
121→							className={`
122→								flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium
123→								transition-all duration-200
124→								${
125→									isSelected
126→										? "bg-accent-light text-accent-text border-2 border-accent"
