  1→import type { UserMapping as UserMappingBase } from "@rudel/api-routes";
  2→import {
  3→	buildDateFilter,
  4→	escapeString,
  5→	queryClickhouse,
  6→} from "../clickhouse.js";
  7→
  8→export interface UserMapping extends UserMappingBase {
  9→	session_count: number;
 10→}
 11→
 12→/**
 13→ * Extract username from project path
 14→ * Pattern: /Users/{username}/... or /home/{username}/...
 15→ */
 16→function extractUsernameFromPath(projectPath: string): string | null {
 17→	const match = projectPath.match(/^\/(?:Users|home)\/([^/]+)\//);
 18→	return match ? (match[1] ?? null) : null;
 19→}
 20→
 21→/**
 22→ * Get user ID to username mappings by extracting usernames from project paths
 23→ */
 24→export async function getUserMappings(
 25→	orgId: string,
 26→	days = 30,
 27→): Promise<UserMapping[]> {
 28→	const org = escapeString(orgId);
 29→	const dateFilter = buildDateFilter(days);
 30→
 31→	const query = `
 32→    SELECT
 33→      user_id,
 34→      project_path,
 35→      count() as sessions
 36→    FROM rudel.session_analytics
 37→    WHERE ${dateFilter}
 38→      AND organization_id = '${org}'
 39→    GROUP BY user_id, project_path
 40→    ORDER BY user_id, sessions DESC
 41→  `;
 42→
 43→	const results = await queryClickhouse<{
 44→		user_id: string;
 45→		project_path: string;
 46→		sessions: number;
 47→	}>(query);
 48→
 49→	// Group by user_id and extract the most common username
 50→	const userMap = new Map<
 51→		string,
 52→		{ username: string | null; totalSessions: number }
 53→	>();
 54→
 55→	for (const row of results) {
 56→		const username = extractUsernameFromPath(row.project_path);
 57→
 58→		if (!userMap.has(row.user_id)) {
 59→			userMap.set(row.user_id, { username, totalSessions: row.sessions });
 60→		} else {
 61→			const existing = userMap.get(row.user_id);
 62→			if (!existing) continue;
 63→			if (username && row.sessions > existing.totalSessions) {
 64→				existing.username = username;
 65→				existing.totalSessions = row.sessions;
 66→			}
 67→		}
 68→	}
 69→
 70→	const mappings: UserMapping[] = [];
 71→	for (const [user_id, data] of userMap.entries()) {
 72→		if (data.username) {
 73→			mappings.push({
 74→				user_id,
 75→				username: data.username,
 76→				session_count: data.totalSessions,
 77→			});
 78→		}
 79→	}
 80→
 81→	return mappings.sort((a, b) => b.session_count - a.session_count);
 82→}
 83→
 84→/**
 85→ * Get a single user mapping by user_id
 86→ */
 87→export async function getUserMapping(
 88→	orgId: string,
 89→	userId: string,
 90→	days = 30,
 91→): Promise<UserMapping | null> {
 92→	const org = escapeString(orgId);
 93→	const uid = escapeString(userId);
 94→	const dateFilter = buildDateFilter(days);
 95→
 96→	const query = `
 97→    SELECT
 98→      user_id,
 99→      project_path,
100→      count() as sessions
101→    FROM rudel.session_analytics
102→    WHERE ${dateFilter}
103→      AND organization_id = '${org}'
104→      AND user_id = '${uid}'
105→    GROUP BY user_id, project_path
106→    ORDER BY sessions DESC
107→    LIMIT 1
108→  `;
109→
110→	const results = await queryClickhouse<{
111→		user_id: string;
112→		project_path: string;
113→		sessions: number;
114→	}>(query);
115→
116→	const [row] = results;
117→	if (!row) {
118→		return null;
119→	}
120→	const username = extractUsernameFromPath(row.project_path);
121→
122→	if (!username) {
123→		return null;
124→	}
125→
126→	return {
127→		user_id: row.user_id,
128→		username,
129→		session_count: row.sessions,
130→	};
131→}
